examples.fromCode:
interface Account { active: boolean; group: string; amount: number }
const total = accounts
  .filter(a => a.active)
  .reduce((sum, a) => sum + a.amount, 0);

examples.toCode:
SELECT SUM(amount) AS total_amount
FROM accounts
WHERE active = true;

